import React, { useState } from 'react';

export default function ColorSliderPicker() {
  const [h, setH] = useState(180);
  const [s, setS] = useState(50);
  const [l, setL] = useState(50);

  // Convert HSL to HEX helper function
  const hslToHex = (h, s, l) => {
    s /= 100;
    l /= 100;
    const a = s * Math.min(l, 1 - l);
    const f = (n) => {
      const k = (n + h / 30) % 12;
      const color = l - a * Math.max(Math.min(k - 3, 9 - k, 1), -1);
      return Math.round(255 * color).toString(16).padStart(2, "0");
    };
    return `#${f(0)}${f(8)}${f(4)}`;
  };

  const hexVal = hslToHex(h, s, l);

  return (
    <div className="w-80 border border-gray-250 rounded-2xl p-5 bg-white shadow-md font-sans">
      {/* Color Preview Box */}
      <div
        className="w-full h-32 rounded-xl mb-6 shadow-inner border border-gray-100 flex items-center justify-center transition-colors"
        style={{ backgroundColor: `hsl(${h}, ${s}%, ${l}%)` }}
      >
        <span className="bg-white/90 text-gray-800 text-xs font-mono font-bold px-3 py-1 rounded-full uppercase tracking-wider shadow-sm">
          {hexVal}
        </span>
      </div>

      {/* Sliders */}
      <div className="flex flex-col gap-4 text-xs font-bold text-gray-500 uppercase">
        <div>
          <div className="flex justify-between mb-1">
            <span>Hue</span>
            <span className="font-mono text-gray-700">{h}°</span>
          </div>
          <input type="range" min="0" max="360" value={h} onChange={(e) => setH(Number(e.target.value))} className="w-full accent-purple-500" />
        </div>

        <div>
          <div className="flex justify-between mb-1">
            <span>Saturation</span>
            <span className="font-mono text-gray-700">{s}%</span>
          </div>
          <input type="range" min="0" max="100" value={s} onChange={(e) => setS(Number(e.target.value))} className="w-full accent-purple-500" />
        </div>

        <div>
          <div className="flex justify-between mb-1">
            <span>Lightness</span>
            <span className="font-mono text-gray-700">{l}%</span>
          </div>
          <input type="range" min="0" max="100" value={l} onChange={(e) => setL(Number(e.target.value))} className="w-full accent-purple-500" />
        </div>
      </div>
    </div>
  );
}
